diffs.replacement:
{
  "name": "V&C",
  "description": "Uma plataforma profissional de gestão e acompanhamento de vendas, focada em simplicidade e alta performance.",
  "requestFramePermissions": []
}

import React, { useState, useRef, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import SaleForm from './components/SaleForm';
import { NavItem, Sale } from './types';
import { 
  Plus, 
  X, 
  History,
  Search,
  List,
  LayoutGrid,
  Command,
  CreditCard,
  Zap,
  Wallet,
  Award
} from 'lucide-react';

const App: React.FC = () => {
  const [activeNav, setActiveNav] = useState<NavItem>(NavItem.Resumos);
  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
  const [viewMode, setViewMode] = useState<'list' | 'pipeline'>('list');
  const [isFabOpen, setIsFabOpen] = useState(false);
  const [savedSales, setSavedSales] = useState<Sale[]>([]);
  const mainRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const data = localStorage.getItem('vc_sales_data');
    if (data) setSavedSales(JSON.parse(data));
  }, []);

  const saveSale = (newSaleData: any) => {
    const saleObj: Sale = {
      numeroPedido: newSaleData.pedido,
      valorProduto: newSaleData.produto,
      valorAssistencia: newSaleData.assistencia,
      valorImpermeabilizacao: newSaleData.impermeabilizacao,
      total: newSaleData.total,
      bonusTotal: newSaleData.bonusTotal,
      servicosExtras: newSaleData.servicosExtras,
      data: new Date().toLocaleDateString('pt-BR')
    };

    const updatedSales = [saleObj, ...savedSales];
    setSavedSales(updatedSales);
    localStorage.setItem('vc_sales_data', JSON.stringify(updatedSales));
    setActiveNav(NavItem.Resumos);
  };

  const formatBRL = (val: number) => 
    new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL', maximumFractionDigits: 0 }).format(val);

  const renderContent = () => {
    const totalFaturado = savedSales.reduce((acc, s) => acc + s.total, 0);
    const totalBonus = savedSales.reduce((acc, s) => acc + (s.bonusTotal || 0), 0);
    const valorTotalGlobal = totalFaturado + totalBonus;

    switch (activeNav) {
      case NavItem.AdicionarVenda:
        return (
          <div className="content-section animate-in fade-in zoom-in-95 duration-500">
            <SaleForm onCancel={() => setActiveNav(NavItem.Resumos)} onSubmit={saveSale} />
          </div>
        );

      case NavItem.Meta:
      case NavItem.Resumos:
        return (
          <div className="content-section space-y-8 pb-10">
            <div className="flex flex-col md:flex-row items-center justify-between gap-6">
               <div>
                  <h2 className="text-5xl font-black text-white uppercase tracking-tighter">V&C</h2>
                  <div className="flex items-center gap-2 mt-1">
                    <div className="w-2 h-2 rounded-full bg-cyan-400 animate-glow"></div>
                    <p className="text-[10px] text-cyan-400 font-black uppercase tracking-[0.3em]">Gestão em Tempo Real</p>
                  </div>
               </div>
               <div className="glass p-1.5 rounded-2xl flex">
                 <button onClick={() => setViewMode('list')} className={`p-3 rounded-xl transition-all ${viewMode === 'list' ? 'bg-white text-black' : 'text-slate-500 hover:text-white'}`}><List size={20}/></button>
                 <button onClick={() => setViewMode('pipeline')} className={`p-3 rounded-xl transition-all ${viewMode === 'pipeline' ? 'bg-white text-black' : 'text-slate-500 hover:text-white'}`}><LayoutGrid size={20}/></button>
               </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
               <div className="glass p-8 rounded-[2.5rem] border-cyan-500/10 overflow-hidden relative group">
                  <div className="absolute top-0 right-0 p-6 opacity-5 group-hover:scale-110 transition-transform">
                     <CreditCard size={80} />
                  </div>
                  <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-2">Faturamento Bruto</span>
                  <h3 className="text-4xl font-black text-white mono mb-2">{formatBRL(totalFaturado)}</h3>
                  <p className="text-[10px] text-cyan-500/60 font-bold uppercase">Total Pago pelos Clientes</p>
               </div>

               <div className="glass p-8 rounded-[2.5rem] border-emerald-500/10 overflow-hidden relative group">
                  <div className="absolute top-0 right-0 p-6 opacity-5 group-hover:scale-110 transition-transform text-emerald-500">
                     <Award size={80} />
                  </div>
                  <span className="text-[10px] font-black text-emerald-500 uppercase tracking-widest block mb-2">Bônus Acumulados</span>
                  <h3 className="text-4xl font-black text-emerald-400 mono mb-2">{formatBRL(totalBonus)}</h3>
                  <p className="text-[10px] text-emerald-500/60 font-bold uppercase">Montagem, Lavagem e Adicionais</p>
               </div>

               <div className="bg-gradient-to-br from-violet-600 to-fuchsia-700 p-8 rounded-[2.5rem] shadow-2xl overflow-hidden relative group md:col-span-2 lg:col-span-1">
                  <div className="absolute top-0 right-0 p-6 opacity-20">
                     <Wallet size={80} className="text-white" />
                  </div>
                  <span className="text-[10px] font-black text-white/50 uppercase tracking-widest block mb-2">Resultado Geral</span>
                  <h3 className="text-4xl font-black text-white mono mb-2">{formatBRL(valorTotalGlobal)}</h3>
                  <div className="flex items-center gap-2 text-[10px] font-bold text-white/70 uppercase mt-4">
                    <Zap size={14} /> Faturamento + Bônus Consolidados
                  </div>
               </div>
            </div>

            <div className="glass rounded-[3rem] p-8 md:p-10">
              <div className="flex items-center justify-between mb-8">
                <div>
                  <h4 className="text-xl font-black text-white uppercase tracking-tighter">Últimos Lançamentos</h4>
                  <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest mt-1">Histórico recente de transações</p>
                </div>
                <button onClick={() => setActiveNav(NavItem.ResumoPedido)} className="bg-white/5 px-6 py-3 rounded-xl text-[10px] font-black text-white uppercase hover:bg-white/10 transition-all border border-white/5">Ver Histórico</button>
              </div>
              <div className="space-y-4">
                {savedSales.length === 0 ? (
                   <div className="py-20 flex flex-col items-center justify-center text-slate-700 border border-dashed border-white/10 rounded-[2rem]">
                      <History size={40} className="mb-4 opacity-20" />
                      <p className="text-[10px] font-black uppercase tracking-widest text-center px-4">Nenhuma venda registrada</p>
                   </div>
                ) : (
                  savedSales.slice(0, 5).map((sale, i) => (
                    <div key={i} className="flex flex-col md:flex-row items-center justify-between p-6 bg-white/5 rounded-3xl border border-white/5 hover:border-white/10 transition-all gap-4 group">
                      <div className="flex items-center gap-5 w-full md:w-auto">
                        <div className="w-12 h-12 rounded-2xl bg-white/5 flex items-center justify-center text-slate-400 group-hover:text-cyan-400 transition-colors">
                          <Search size={20} />
                        </div>
                        <div>
                          <div className="text-lg font-black text-white uppercase tracking-tight">PEDIDO {sale.numeroPedido}</div>
                          <div className="text-[10px] text-slate-500 font-bold uppercase mono">{sale.data}</div>
                        </div>
                      </div>
                      <div className="flex items-center gap-10 w-full md:w-auto justify-between md:justify-end border-t md:border-t-0 border-white/5 pt-4 md:pt-0">
                        <div className="text-right">
                          <div className="text-[9px] text-emerald-500 font-black uppercase mb-1">Bônus</div>
                          <div className="text-xl font-black text-emerald-400 mono leading-none">{formatBRL(sale.bonusTotal || 0)}</div>
                        </div>
                        <div className="text-right">
                          <div className="text-[9px] text-slate-600 font-black uppercase mb-1">Total</div>
                          <div className="text-2xl font-black text-white mono tracking-tighter leading-none">{formatBRL(sale.total)}</div>
                        </div>
                      </div>
                    </div>
                  ))
                )}
              </div>
            </div>
          </div>
        );

      case NavItem.ResumoPedido:
        return (
          <div className="content-section pb-20 px-2">
            <div className="glass rounded-[3rem] p-8 md:p-12 relative overflow-hidden">
               <div className="flex items-center justify-between mb-10">
                  <h3 className="text-3xl font-black text-white uppercase tracking-tighter">Histórico Completo</h3>
                  <div className="text-[10px] font-black text-cyan-400 bg-cyan-400/10 px-4 py-2 rounded-xl uppercase border border-cyan-400/20">{savedSales.length} Registros</div>
               </div>
               <div className="grid grid-cols-1 gap-6">
                  {savedSales.map((sale, i) => (
                    <div key={i} className="group flex flex-col lg:flex-row gap-6 p-8 bg-white/5 border border-white/5 rounded-[2.5rem] hover:bg-white/[0.07] transition-all">
                      <div className="flex-1">
                         <div className="flex items-center gap-3 mb-2">
                            <span className="text-[10px] font-black bg-cyan-500 text-black px-2 py-0.5 rounded-md uppercase tracking-tighter">Processado</span>
                            <div className="text-xl font-black text-white tracking-tight uppercase">Pedido: {sale.numeroPedido}</div>
                         </div>
                         <div className="text-[10px] text-slate-500 font-bold uppercase tracking-widest mb-4">Lançado em {sale.data}</div>
                         <div className="flex flex-wrap gap-2">
                            <span className="text-[9px] font-black bg-white/10 text-cyan-400 px-3 py-1.5 rounded-xl uppercase border border-white/5">Prod: {formatBRL(sale.valorProduto)}</span>
                            <span className="text-[9px] font-black bg-white/10 text-blue-400 px-3 py-1.5 rounded-xl uppercase border border-white/5">Assis: {formatBRL(sale.valorAssistencia)}</span>
                            {sale.servicosExtras.map((e, idx) => (
                              <span key={idx} className="text-[9px] font-black bg-emerald-500/10 text-emerald-400 px-3 py-1.5 rounded-xl uppercase border border-emerald-500/20">{e}</span>
                            ))}
                         </div>
                      </div>
                      <div className="flex flex-row lg:flex-col justify-between items-end lg:w-56 pt-6 lg:pt-0 border-t lg:border-t-0 border-white/10">
                         <div className="text-right">
                            <div className="text-[9px] text-emerald-500 font-black uppercase">Crédito Bônus</div>
                            <div className="text-2xl font-black text-emerald-400 mono leading-none">{formatBRL(sale.bonusTotal || 0)}</div>
                         </div>
                         <div className="text-right mt-auto">
                            <div className="text-[9px] text-slate-600 font-black uppercase">Total Pedido</div>
                            <div className="text-3xl font-black text-white mono tracking-tighter leading-none">{formatBRL(sale.total)}</div>
                         </div>
                      </div>
                    </div>
                  ))}
               </div>
            </div>
          </div>
        );

      default:
        return <div className="content-section text-center py-40 uppercase font-black text-slate-800 tracking-[1em]">Módulo em Expansão</div>;
    }
  };

  return (
    <div className="min-h-screen flex bg-[#05020a] overflow-hidden selection:bg-cyan-500 selection:text-black">
      <Sidebar isCollapsed={isSidebarCollapsed} setIsCollapsed={setIsSidebarCollapsed} activeItem={activeNav} onSelect={setActiveNav} />

      <div className={`flex-1 flex flex-col min-w-0 h-screen relative transition-all duration-500 ${isSidebarCollapsed ? 'md:ml-24' : 'md:ml-64'}`}>
        <Header />
        <main ref={mainRef} className="flex-1 overflow-x-hidden overflow-y-auto px-6 md:px-12 py-8">
          <div className="max-w-[1300px] mx-auto w-full">
            {renderContent()}
          </div>
        </main>

        <div className="fixed bottom-10 right-10 z-[100]">
          {isFabOpen && (
            <div className="absolute bottom-24 right-0 flex flex-col gap-4 animate-in slide-in-from-bottom-10 fade-in duration-500">
              <button 
                onClick={() => { setActiveNav(NavItem.AdicionarVenda); setIsFabOpen(false); }}
                className="flex items-center gap-4 bg-white text-black px-8 py-5 rounded-[2rem] shadow-[0_20px_60px_rgba(0,0,0,0.8)] whitespace-nowrap hover:scale-105 transition-all"
              >
                <Plus size={24} />
                <span className="font-black text-xs uppercase tracking-widest">Lançar Nova Venda</span>
              </button>
            </div>
          )}
          <button 
            onClick={() => setIsFabOpen(!isFabOpen)}
            className={`w-20 h-20 rounded-[2.5rem] flex items-center justify-center shadow-2xl transition-all duration-500 animate-pulse-neon bg-gradient-to-br from-cyan-400 to-violet-600 text-white ${isFabOpen ? 'rotate-45' : ''}`}
          >
            {isFabOpen ? <X size={32} /> : <Command size={32} />}
          </button>
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Save, X, Terminal, CheckSquare, Square, CreditCard, Award, DollarSign } from 'lucide-react';

interface SaleFormProps {
  onCancel: () => void;
  onSubmit: (sale: any) => void;
}

const BONUS_VALUES = {
  montagem: 10,
  lavagem: 40,
  almofada: 10,
  pes_guarda_roupa: 7,
  impermeabilizacao_bonus: 40
};

const SaleForm: React.FC<SaleFormProps> = ({ onCancel, onSubmit }) => {
  const [pedido, setPedido] = useState('');
  const [produto, setProduto] = useState<number>(0);
  const [assistencia, setAssistencia] = useState<number>(0);
  const [impermeabilizacao, setImpermeabilizacao] = useState<number>(0);
  const [total, setTotal] = useState(0);

  const [extras, setExtras] = useState({
    montagem: false,
    lavagem: false,
    almofada: false,
    pes_guarda_roupa: false,
    impermeabilizacao_bonus: false
  });

  const firstInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    setTotal(produto + assistencia + impermeabilizacao);
  }, [produto, assistencia, impermeabilizacao]);

  useEffect(() => {
    if (firstInputRef.current) firstInputRef.current.focus();
  }, []);

  const calculateBonus = () => {
    let bonusTotal = 0;
    Object.keys(extras).forEach(key => {
      if (extras[key as keyof typeof extras]) {
        bonusTotal += BONUS_VALUES[key as keyof typeof BONUS_VALUES];
      }
    });
    return bonusTotal;
  };

  const getSelectedLabels = () => {
    const labels: string[] = [];
    if (extras.montagem) labels.push("Montagem (R$10)");
    if (extras.lavagem) labels.push("Lavagem (R$40)");
    if (extras.almofada) labels.push("Almofada (R$10)");
    if (extras.pes_guarda_roupa) labels.push("Pés G-R (R$7)");
    if (extras.impermeabilizacao_bonus) labels.push("Impermeab. (R$40)");
    return labels;
  };

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);
  };

  const handleInputChange = (setter: React.Dispatch<React.SetStateAction<number>>, value: string) => {
    const numericValue = parseFloat(value.replace(/[^\d]/g, '')) / 100;
    setter(isNaN(numericValue) ? 0 : numericValue);
  };

  return (
    <div className="w-full max-w-4xl mx-auto pb-20">
      <div className="glass rounded-[3.5rem] overflow-hidden border border-white/10 shadow-[0_0_100px_rgba(0,0,0,0.5)]">
        <div className="p-8 md:p-14">
          <div className="flex items-center justify-between mb-12">
            <div>
              <div className="flex items-center gap-3 text-cyan-400 mb-2">
                <Terminal size={18} className="animate-pulse" />
                <span className="text-[10px] font-black uppercase tracking-[0.4em]">Terminal V&C</span>
              </div>
              <h2 className="text-3xl font-black text-white uppercase tracking-tighter">Novo Lançamento</h2>
            </div>
            <button onClick={onCancel} className="bg-white/5 p-4 rounded-2xl text-slate-500 hover:text-white hover:bg-white/10 transition-all border border-white/5">
              <X size={24} />
            </button>
          </div>

          <form className="space-y-10" onSubmit={(e) => {
            e.preventDefault();
            onSubmit({ pedido, produto, assistencia, impermeabilizacao, total, bonusTotal: calculateBonus(), servicosExtras: getSelectedLabels() });
          }}>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div className="space-y-3">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Número do Pedido</label>
                <input
                  ref={firstInputRef}
                  type="text"
                  required
                  autoCapitalize="characters"
                  value={pedido}
                  onChange={(e) => setPedido(e.target.value.toUpperCase())}
                  placeholder="DIGITE O CÓDIGO"
                  className="w-full bg-white/5 border border-white/10 p-5 rounded-2xl text-white font-black mono text-xl focus:ring-2 focus:ring-cyan-500 transition-all outline-none"
                />
              </div>
              <div className="space-y-3">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Valor do Produto</label>
                <input
                  type="text"
                  inputMode="decimal"
                  required
                  value={produto === 0 ? "" : formatCurrency(produto)}
                  onChange={(e) => handleInputChange(setProduto, e.target.value)}
                  placeholder="R$ 0,00"
                  className="w-full bg-white/5 border border-white/10 p-5 rounded-2xl text-white font-black mono text-xl focus:ring-2 focus:ring-violet-500 transition-all outline-none"
                />
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div className="space-y-3">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Assistência Técnica</label>
                <input
                  type="text"
                  inputMode="decimal"
                  value={assistencia === 0 ? "" : formatCurrency(assistencia)}
                  onChange={(e) => handleInputChange(setAssistencia, e.target.value)}
                  placeholder="R$ 0,00"
                  className="w-full bg-white/5 border border-white/10 p-5 rounded-2xl text-white font-bold mono focus:ring-2 focus:ring-blue-500 transition-all outline-none"
                />
              </div>
              <div className="space-y-3">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Impermeabilização</label>
                <input
                  type="text"
                  inputMode="decimal"
                  value={impermeabilizacao === 0 ? "" : formatCurrency(impermeabilizacao)}
                  onChange={(e) => handleInputChange(setImpermeabilizacao, e.target.value)}
                  placeholder="R$ 0,00"
                  className="w-full bg-white/5 border border-white/10 p-5 rounded-2xl text-white font-bold mono focus:ring-2 focus:ring-fuchsia-500 transition-all outline-none"
                />
              </div>
            </div>

            <div className="bg-white/5 p-8 rounded-[2.5rem] border border-white/5 shadow-inner">
              <div className="flex items-center gap-3 mb-6">
                <Award size={18} className="text-emerald-400" />
                <h4 className="text-[11px] font-black text-white uppercase tracking-[0.3em]">Bônus Adicionais</h4>
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-3">
                {[
                  { id: 'montagem', label: 'Montagem', val: 'R$10' },
                  { id: 'lavagem', label: 'Lavagem', val: 'R$40' },
                  { id: 'almofada', label: 'Almofada', val: 'R$10' },
                  { id: 'pes_guarda_roupa', label: 'Pés G-R', val: 'R$7' },
                  { id: 'impermeabilizacao_bonus', label: 'Impermeab.', val: 'R$40' }
                ].map((item) => (
                  <button
                    key={item.id}
                    type="button"
                    onClick={() => setExtras(prev => ({...prev, [item.id]: !prev[item.id as keyof typeof extras]}))}
                    className={`flex items-center justify-between p-4 rounded-2xl border transition-all duration-300 ${
                      extras[item.id as keyof typeof extras] 
                      ? 'bg-emerald-500 text-black border-emerald-400 shadow-[0_0_20px_rgba(16,185,129,0.4)] scale-[1.03]' 
                      : 'bg-white/5 border-white/5 text-slate-500 hover:border-white/20'
                    }`}
                  >
                    <div className="flex flex-col items-start">
                       <span className="text-[10px] font-black uppercase leading-tight">{item.label}</span>
                       <span className={`text-[8px] mono font-bold ${extras[item.id as keyof typeof extras] ? 'text-black' : 'opacity-40'}`}>{item.val}</span>
                    </div>
                    {extras[item.id as keyof typeof extras] ? <CheckSquare size={16} /> : <Square size={16} />}
                  </button>
                ))}
              </div>
            </div>

            <div className="p-[1px] rounded-[3rem] bg-gradient-to-r from-cyan-400 via-violet-600 to-emerald-500 shadow-2xl">
              <div className="bg-[#0a051a] rounded-[2.9rem] p-8 flex flex-col md:flex-row items-center justify-between gap-8">
                 <div className="text-center md:text-left">
                    <div className="flex items-center justify-center md:justify-start gap-2 mb-1">
                      <DollarSign size={14} className="text-slate-500" />
                      <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Valor do Cliente</span>
                    </div>
                    <div className="text-3xl font-black text-white mono tracking-tighter">{formatCurrency(total)}</div>
                 </div>

                 <div className="w-px h-16 bg-white/10 hidden md:block"></div>

                 <div className="text-center md:text-right">
                    <div className="flex items-center justify-center md:justify-end gap-2 mb-1">
                      <Award size={14} className="text-emerald-500" />
                      <span className="text-[10px] font-black text-emerald-500 uppercase tracking-widest">Bônus Calculado</span>
                    </div>
                    <div className="text-3xl font-black text-emerald-400 mono tracking-tighter">+{formatCurrency(calculateBonus())}</div>
                 </div>
              </div>
            </div>

            <button type="submit" className="w-full bg-white text-black py-6 rounded-[2rem] font-black text-sm uppercase tracking-[0.2em] hover:bg-cyan-400 transition-all hover:scale-[1.02] shadow-[0_20px_50px_rgba(0,0,0,0.3)]">
              Gravar Lançamento
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

export default SaleForm;
